// Generate fish shell completion files.
//
// Output format:
// ```fish
// # Auto-generated by completion-forge
// complete -c tool -n "__fish_use_subcommand" -a "subcommand" -d "Description"
// complete -c tool -n "__fish_seen_subcommand_from subcommand" -l flag-name -d "Flag desc"
// ```

use std::path::Path;

use crate::error::{ForgeError, ForgeResult};
use crate::ir::CompletionSpec;

/// Generate a fish completion file and return its path.
///
/// # Errors
/// Returns [`ForgeError::Io`] if the file cannot be written.
pub fn generate(spec: &CompletionSpec, output_dir: &Path) -> ForgeResult<String> {
    let mut lines = Vec::new();
    lines.push(format!(
        "# Auto-generated fish completions for {} by completion-forge",
        spec.name
    ));
    lines.push(format!("# {}", spec.description));
    lines.push(String::new());

    // Build list of all command names (primary + aliases).
    let commands: Vec<&str> = std::iter::once(spec.name.as_str())
        .chain(spec.aliases.iter().map(String::as_str))
        .collect();

    for cmd in &commands {
        // Subcommand completions.
        for group in &spec.groups {
            lines.push(format!(
                "complete -c {cmd} -n \"__fish_use_subcommand\" -a {name} -d {desc}",
                name = shell_quote(&group.name),
                desc = shell_quote(&format!("{} {}", group.glyph, group.description)),
            ));
        }

        // Flag completions per subcommand.
        for group in &spec.groups {
            for flag in &group.flags {
                let condition = format!("__fish_seen_subcommand_from {}", group.name);
                let req = if flag.required { " -r" } else { "" };
                lines.push(format!(
                    "complete -c {cmd} -n {cond}{req} -l {name} -d {desc}",
                    cond = shell_quote(&condition),
                    name = shell_quote(&flag.name),
                    desc = shell_quote(&flag.description),
                ));
            }
        }

        if commands.len() > 1 {
            lines.push(String::new());
        }
    }

    let content = lines.join("\n") + "\n";
    let filename = format!("{}.fish", spec.name);
    let path = output_dir.join(&filename);
    std::fs::write(&path, &content).map_err(|e| ForgeError::io(&path, e))?;

    Ok(path.display().to_string())
}

/// Simple shell quoting — wraps in single quotes, escaping internal quotes.
fn shell_quote(s: &str) -> String {
    if s.contains('\'') {
        format!("\"{}\"", s.replace('"', "\\\""))
    } else {
        format!("'{s}'")
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::ir::{CommandGroup, CompletionFlag, CompletionOp, Glyph};

    fn sample_spec() -> CompletionSpec {
        CompletionSpec {
            name: "petstore".into(),
            icon: "\u{2601}".into(),
            aliases: vec!["ps".into()],
            description: "Pet store API".into(),
            groups: vec![CommandGroup {
                name: "pets".into(),
                description: "Pet operations".into(),
                glyph: Glyph::View,
                operations: vec![CompletionOp {
                    name: "list-pets".into(),
                    description: "List all pets".into(),
                    method: "GET".into(),
                }],
                flags: vec![
                    CompletionFlag {
                        name: "limit".into(),
                        description: "Maximum results".into(),
                        required: false,
                    },
                    CompletionFlag {
                        name: "id".into(),
                        description: "Pet identifier".into(),
                        required: true,
                    },
                ],
            }],
        }
    }

    #[test]
    fn generate_fish_file() {
        let dir = tempfile::tempdir().unwrap();
        let spec = sample_spec();
        let path = generate(&spec, dir.path()).unwrap();
        assert!(path.ends_with("petstore.fish"));

        let content = std::fs::read_to_string(&path).unwrap();
        assert!(content.contains("complete -c petstore"));
        assert!(content.contains("complete -c ps"));
        assert!(content.contains("__fish_use_subcommand"));
        assert!(content.contains("-a 'pets'"));
    }

    #[test]
    fn fish_flags_generated() {
        let dir = tempfile::tempdir().unwrap();
        let spec = sample_spec();
        let path = generate(&spec, dir.path()).unwrap();

        let content = std::fs::read_to_string(&path).unwrap();
        assert!(content.contains("-l 'limit'"));
        assert!(content.contains("-l 'id'"));
        // Required flag should have -r
        assert!(content.contains("-r -l 'id'"));
    }

    #[test]
    fn fish_header_comment() {
        let dir = tempfile::tempdir().unwrap();
        let spec = sample_spec();
        let path = generate(&spec, dir.path()).unwrap();

        let content = std::fs::read_to_string(&path).unwrap();
        assert!(content.starts_with("# Auto-generated fish completions"));
        assert!(content.contains("Pet store API"));
    }

    #[test]
    fn shell_quote_simple() {
        assert_eq!(shell_quote("hello"), "'hello'");
    }

    #[test]
    fn shell_quote_with_single_quotes() {
        assert_eq!(shell_quote("it's"), "\"it's\"");
    }

    #[test]
    fn empty_groups_produces_minimal_output() {
        let dir = tempfile::tempdir().unwrap();
        let spec = CompletionSpec {
            name: "empty".into(),
            icon: String::new(),
            aliases: vec![],
            description: "Empty tool".into(),
            groups: vec![],
        };
        let path = generate(&spec, dir.path()).unwrap();
        let content = std::fs::read_to_string(&path).unwrap();
        assert!(content.starts_with("# Auto-generated"));
        // Should not have any complete commands
        assert!(!content.contains("complete -c"));
    }

    #[test]
    fn test_generate_required_flag_has_r() {
        let dir = tempfile::tempdir().unwrap();
        let spec = CompletionSpec {
            name: "reqtest".into(),
            icon: String::new(),
            aliases: vec![],
            description: "Required flag test".into(),
            groups: vec![CommandGroup {
                name: "items".into(),
                description: "Item operations".into(),
                glyph: Glyph::View,
                operations: vec![],
                flags: vec![
                    CompletionFlag {
                        name: "id".into(),
                        description: "Item ID".into(),
                        required: true,
                    },
                    CompletionFlag {
                        name: "verbose".into(),
                        description: "Verbose output".into(),
                        required: false,
                    },
                ],
            }],
        };

        let path = generate(&spec, dir.path()).unwrap();
        let content = std::fs::read_to_string(&path).unwrap();

        // Required flag "id" must have -r
        let id_line = content.lines().find(|l| l.contains("-l 'id'")).unwrap();
        assert!(
            id_line.contains(" -r "),
            "required flag 'id' should have -r: {id_line}"
        );

        // Optional flag "verbose" must NOT have -r
        let verbose_line = content
            .lines()
            .find(|l| l.contains("-l 'verbose'"))
            .unwrap();
        assert!(
            !verbose_line.contains("-r"),
            "optional flag 'verbose' should not have -r: {verbose_line}"
        );
    }

    #[test]
    fn shell_quote_with_double_quotes() {
        let result = shell_quote("it's a \"test\"");
        assert_eq!(result, "\"it's a \\\"test\\\"\"");
    }

    #[test]
    fn shell_quote_empty_string() {
        assert_eq!(shell_quote(""), "''");
    }

    #[test]
    fn shell_quote_special_characters() {
        assert_eq!(shell_quote("hello world"), "'hello world'");
        assert_eq!(shell_quote("a\tb"), "'a\tb'");
        assert_eq!(shell_quote("$var"), "'$var'");
        assert_eq!(shell_quote("a&b"), "'a&b'");
    }

    #[test]
    fn generate_multiple_groups() {
        let dir = tempfile::tempdir().unwrap();
        let spec = CompletionSpec {
            name: "multi".into(),
            icon: String::new(),
            aliases: vec![],
            description: "Multiple groups".into(),
            groups: vec![
                CommandGroup {
                    name: "users".into(),
                    description: "User operations".into(),
                    glyph: Glyph::View,
                    operations: vec![CompletionOp {
                        name: "list-users".into(),
                        description: "List users".into(),
                        method: "GET".into(),
                    }],
                    flags: vec![CompletionFlag {
                        name: "limit".into(),
                        description: "Max results".into(),
                        required: false,
                    }],
                },
                CommandGroup {
                    name: "orders".into(),
                    description: "Order operations".into(),
                    glyph: Glyph::Create,
                    operations: vec![CompletionOp {
                        name: "create-order".into(),
                        description: "Create order".into(),
                        method: "POST".into(),
                    }],
                    flags: vec![CompletionFlag {
                        name: "product".into(),
                        description: "Product ID".into(),
                        required: true,
                    }],
                },
            ],
        };

        let path = generate(&spec, dir.path()).unwrap();
        let content = std::fs::read_to_string(&path).unwrap();
        assert!(content.contains("-a 'users'"));
        assert!(content.contains("-a 'orders'"));
        assert!(content.contains("-l 'limit'"));
        assert!(content.contains("-l 'product'"));
        assert!(content.contains("-r -l 'product'"));
    }

    #[test]
    fn generate_glyph_in_description() {
        let dir = tempfile::tempdir().unwrap();
        let spec = CompletionSpec {
            name: "glyphtest".into(),
            icon: String::new(),
            aliases: vec![],
            description: "Glyph test".into(),
            groups: vec![CommandGroup {
                name: "data".into(),
                description: "Data ops".into(),
                glyph: Glyph::Update,
                operations: vec![],
                flags: vec![],
            }],
        };

        let path = generate(&spec, dir.path()).unwrap();
        let content = std::fs::read_to_string(&path).unwrap();
        assert!(content.contains("\u{21BB}"), "should contain Update glyph ↻");
    }

    #[test]
    fn generate_fish_multiple_aliases() {
        let dir = tempfile::tempdir().unwrap();
        let spec = CompletionSpec {
            name: "tool".into(),
            icon: String::new(),
            aliases: vec!["t".into(), "tl".into()],
            description: "Tool".into(),
            groups: vec![CommandGroup {
                name: "stuff".into(),
                description: "Stuff".into(),
                glyph: Glyph::Manage,
                operations: vec![],
                flags: vec![],
            }],
        };

        let path = generate(&spec, dir.path()).unwrap();
        let content = std::fs::read_to_string(&path).unwrap();
        assert!(content.contains("complete -c tool"));
        assert!(content.contains("complete -c t "));
        assert!(content.contains("complete -c tl "));
    }

    #[test]
    fn test_generate_no_aliases_no_extra_blank_lines() {
        let dir = tempfile::tempdir().unwrap();
        let spec = CompletionSpec {
            name: "noalias".into(),
            icon: String::new(),
            aliases: vec![],
            description: "No aliases".into(),
            groups: vec![CommandGroup {
                name: "things".into(),
                description: "Thing operations".into(),
                glyph: Glyph::View,
                operations: vec![CompletionOp {
                    name: "list".into(),
                    description: "List things".into(),
                    method: "GET".into(),
                }],
                flags: vec![],
            }],
        };

        let path = generate(&spec, dir.path()).unwrap();
        let content = std::fs::read_to_string(&path).unwrap();

        // With no aliases, there's only one command block — no extra blank line
        // separators between alias blocks should appear. Check that there are
        // no consecutive blank lines.
        assert!(
            !content.contains("\n\n\n"),
            "should not have triple newlines (extra blank lines): {content:?}"
        );
    }

    #[test]
    fn shell_quote_unicode() {
        assert_eq!(shell_quote("◈ View ops"), "'◈ View ops'");
    }

    #[test]
    fn shell_quote_newline() {
        assert_eq!(shell_quote("line1\nline2"), "'line1\nline2'");
    }

    #[test]
    fn generate_fish_ends_with_newline() {
        let dir = tempfile::tempdir().unwrap();
        let spec = sample_spec();
        let path = generate(&spec, dir.path()).unwrap();
        let content = std::fs::read_to_string(&path).unwrap();
        assert!(content.ends_with('\n'), "fish file should end with newline");
    }

    #[test]
    fn generate_fish_subcommand_description_includes_glyph() {
        let dir = tempfile::tempdir().unwrap();
        let spec = CompletionSpec {
            name: "test".into(),
            icon: String::new(),
            aliases: vec![],
            description: "Test".into(),
            groups: vec![CommandGroup {
                name: "items".into(),
                description: "Item operations".into(),
                glyph: Glyph::Execute,
                operations: vec![],
                flags: vec![],
            }],
        };
        let path = generate(&spec, dir.path()).unwrap();
        let content = std::fs::read_to_string(&path).unwrap();
        assert!(
            content.contains("\u{25B8} Item operations"),
            "description should include glyph: {content}"
        );
    }
}
